CREATE OR REPLACE FUNCTION public.update_sale_reverse(_sale_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE _sale RECORD; _payments_count INTEGER; _allowed_payments INTEGER; _paid_installments INTEGER; BEGIN SELECT * INTO _sale FROM public.sales WHERE id = _sale_id FOR UPDATE; IF _sale IS NULL THEN RAISE EXCEPTION 'sale not found'; END IF; IF NOT (public.is_shop_member(auth.uid(), _sale.shop_id) OR public.is_super_admin(auth.uid())) THEN RAISE EXCEPTION 'not authorized'; END IF; IF _sale.status IN ('cancelled','returned','partial_return') THEN RAISE EXCEPTION 'cancelled or returned invoice cannot be edited'; END IF; SELECT COUNT(*) INTO _payments_count FROM public.customer_payments WHERE sale_id = _sale_id; _allowed_payments := 0; IF _sale.paid > 0 THEN _allowed_payments := 1; END IF; IF _payments_count > _allowed_payments THEN RAISE EXCEPTION 'invoice has extra payments; cannot edit'; END IF; SELECT COUNT(*) INTO _paid_installments FROM public.installment_schedules WHERE sale_id = _sale_id AND COALESCE(paid_amount,0) > 0; IF _paid_installments > 0 THEN RAISE EXCEPTION 'some installments already paid; cannot edit'; END IF; IF _sale.customer_id IS NOT NULL AND _sale.due > 0 THEN UPDATE public.customers SET current_balance = current_balance - _sale.due WHERE id = _sale.customer_id AND shop_id = _sale.shop_id; END IF; DELETE FROM public.sale_items WHERE sale_id = _sale_id; DELETE FROM public.installment_schedules WHERE sale_id = _sale_id; DELETE FROM public.customer_payments WHERE sale_id = _sale_id; END; $$;